import{bQ as a,aL as e,u as r,G as d}from"./chunks/framework.D06dwy5q.js";const B=JSON.parse('{"title":"单机到集群","description":"","frontmatter":{},"headers":[],"relativePath":"00.互联网与架构基础/07-单机到集群.md","filePath":"00.互联网与架构基础/07-单机到集群.md","lastUpdated":null}'),p={name:"00.互联网与架构基础/07-单机到集群.md"};function A(E,t,i,o,h,l){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="单机到集群" tabindex="-1">单机到集群 <a class="header-anchor" href="#单机到集群" aria-label="Permalink to &quot;单机到集群&quot;">​</a></h1><p>最开始做一个网站，所有东西放在一台服务器上很自然：Nginx、后端程序、数据库、静态文件都在一起。访问量不大时，这种方式清楚、直接，出问题也容易找。</p><p>后来问题会慢慢出现：CPU 和内存不够，磁盘快满了，机器重启时整个网站都停了，发布一次要影响所有用户。集群就是从这些问题里长出来的。</p><h2 id="一、一台机器" tabindex="-1">一、一台机器 <a class="header-anchor" href="#一、一台机器" aria-label="Permalink to &quot;一、一台机器&quot;">​</a></h2><p>单机部署大概长这样：</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20Server%5B%22%E4%B8%80%E5%8F%B0%E6%9C%8D%E5%8A%A1%E5%99%A8%22%5D%0A%20%20Nginx%5B%22Nginx%22%5D%0A%20%20App%5B%22%E5%90%8E%E7%AB%AF%E5%BA%94%E7%94%A8%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%20%20Files%5B%22%E9%9D%99%E6%80%81%E6%96%87%E4%BB%B6%22%5D%0A%0A%20%20User%20--%3E%20Server%0A%20%20Server%20--%3E%20Nginx%0A%20%20Nginx%20--%3E%20App%0A%20%20App%20--%3E%20DB%0A%20%20Nginx%20--%3E%20Files%0A"></div><p>优点很明显：结构简单，网络路径短，日志集中，登录一台机器基本能看到所有东西。缺点也明显：这台机器坏了，入口、应用、数据库和文件都受影响。</p><p>单机不是错误。内部小工具、早期项目、访问量很小的网站，用单机加备份和监控也能跑很久。</p><h2 id="二、给机器加配置" tabindex="-1">二、给机器加配置 <a class="header-anchor" href="#二、给机器加配置" aria-label="Permalink to &quot;二、给机器加配置&quot;">​</a></h2><p>压力上来时，最直接的办法是给这台机器加配置。CPU 从 4 核升到 8 核，内存从 8G 升到 32G，磁盘换成更快的云盘，这叫垂直扩容。</p><p>垂直扩容改动少，应用结构基本不用变。但机器规格总有上限，升级可能要停机，成本也会越来越高。更重要的是，单机故障的问题还在。</p><h2 id="三、多跑几个实例" tabindex="-1">三、多跑几个实例 <a class="header-anchor" href="#三、多跑几个实例" aria-label="Permalink to &quot;三、多跑几个实例&quot;">​</a></h2><p>另一种办法是增加机器数量。一个后端实例扛不住，就启动多个实例；一台 Web 节点不够，就加更多 Web 节点。入口层用负载均衡把请求分给它们。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20User%5B%22%E7%94%A8%E6%88%B7%22%5D%0A%20%20LB%5B%22%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%22%5D%0A%20%20App1%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%201%22%5D%0A%20%20App2%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%202%22%5D%0A%20%20App3%5B%22%E5%BA%94%E7%94%A8%E5%AE%9E%E4%BE%8B%203%22%5D%0A%20%20DB%5B%22%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%0A%20%20User%20--%3E%20LB%0A%20%20LB%20--%3E%20App1%0A%20%20LB%20--%3E%20App2%0A%20%20LB%20--%3E%20App3%0A%20%20App1%20--%3E%20DB%0A%20%20App2%20--%3E%20DB%0A%20%20App3%20--%3E%20DB%0A"></div><p>这就是水平扩容。它能增加处理能力，也能让某个应用实例挂掉时，入口层把请求转给其他实例。</p><h2 id="四、状态放哪里" tabindex="-1">四、状态放哪里 <a class="header-anchor" href="#四、状态放哪里" aria-label="Permalink to &quot;四、状态放哪里&quot;">​</a></h2><p>多实例以后，第一个容易踩到的是状态。</p><p>比如登录 Session 只保存在某一台应用服务器内存里。用户第一次请求打到实例 1，第二次请求被负载均衡转到实例 2，实例 2 不认识这个 Session，用户就会被要求重新登录。</p><p>常见处理方式：</p><table tabindex="0"><thead><tr><th>状态类型</th><th>常见做法</th></tr></thead><tbody><tr><td>登录 Session</td><td>放到 Redis、数据库，或使用 Token</td></tr><tr><td>上传文件</td><td>放到对象存储、共享存储</td></tr><tr><td>本地缓存</td><td>设置过期时间，或改成集中缓存</td></tr><tr><td>定时任务</td><td>控制只有一个实例执行，或交给调度系统</td></tr></tbody></table><p>多实例应用更适合把状态放到外部系统里。请求进到任意实例，都能从数据库、缓存、对象存储拿到需要的数据。</p><h2 id="五、文件放哪里" tabindex="-1">五、文件放哪里 <a class="header-anchor" href="#五、文件放哪里" aria-label="Permalink to &quot;五、文件放哪里&quot;">​</a></h2><p>单机时代，上传文件放在本机目录里就能用。多实例以后，文件只在某台机器上，其他实例访问不到。</p><p>常见做法：</p><table tabindex="0"><thead><tr><th>方式</th><th>适合场景</th></tr></thead><tbody><tr><td>共享文件系统</td><td>多台机器挂同一份目录</td></tr><tr><td>对象存储</td><td>图片、附件、备份包、静态资源</td></tr><tr><td>分布式存储</td><td>更大规模、更高可靠性的存储需求</td></tr></tbody></table><p>对象存储在 Web 系统里很常见。用户上传图片后，后端把文件写到对象存储，数据库只保存文件地址、大小、类型和归属信息。应用实例重建或扩容时，不依赖某台机器上的本地文件。</p><h2 id="六、压力转到数据库" tabindex="-1">六、压力转到数据库 <a class="header-anchor" href="#六、压力转到数据库" aria-label="Permalink to &quot;六、压力转到数据库&quot;">​</a></h2><p>应用实例多了，压力经常转移到数据库。前面加了 10 个应用实例，数据库连接数、查询量、写入量也会跟着涨。</p><p>常见处理手段包括连接池、索引优化、读写分离、缓存、分库分表。这些东西不会第一天全部出现，通常是数据库开始变慢以后逐步加上去。</p><p>单机到集群的变化可以压成一句话：程序从“只考虑本机”变成“要考虑多个实例如何共享状态、分摊流量、避开单点”。</p>',30)])])}const s=a(p,[["render",A]]);export{B as __pageData,s as default};
